pub(crate) fn is_generated_intrinsic_placeholder(crate_name: &str, path: &str) -> bool {
    if is_generated_intrinsic_crate(crate_name) {
        is_generated_intrinsic_canonical_path(path)
    } else if matches!(crate_name, "cuda_device" | "cuda-device") {
        is_generated_intrinsic_compatibility_path(path)
    } else {
        false
    }
}
